# Create a PIM eligible assignment via Azure REST API
# (no direct az CLI command for eligible assignments as of 2026)

# Variables
SUB='11111111-1111-1111-1111-111111111111'
PRINCIPAL='00000000-0000-0000-0000-000000000001'
OWNER_ROLE='8e3af657-a8ff-443c-a75c-2fe8c4bcb635'
SCOPE="/subscriptions/$SUB"
TOKEN=$(az account get-access-token --query accessToken -o tsv)

# Create an eligible assignment (PIM v3 API)
curl -sX PUT \
  "https://management.azure.com${SCOPE}/providers/Microsoft.Authorization/roleEligibilityScheduleRequests/$(uuidgen)?api-version=2022-04-01-preview" \
  -H "Authorization: Bearer $TOKEN" \
  -H 'Content-Type: application/json' \
  -d "{
    \"properties\": {
      \"requestType\": \"AdminAssign\",
      \"principalId\": \"$PRINCIPAL\",
      \"roleDefinitionId\": \"$SCOPE/providers/Microsoft.Authorization/roleDefinitions/$OWNER_ROLE\",
      \"justification\": \"Platform on-call Owner access\",
      \"scheduleInfo\": {
        \"expiration\": { \"type\": \"NoExpiration\" }
      }
    }
  }" | jq '{id:.id,status:.properties.status}'

# Activate an eligible assignment (done by the eligible principal themselves)
curl -sX PUT \
  "https://management.azure.com${SCOPE}/providers/Microsoft.Authorization/roleAssignmentScheduleRequests/$(uuidgen)?api-version=2022-04-01-preview" \
  -H "Authorization: Bearer $TOKEN" \
  -H 'Content-Type: application/json' \
  -d "{
    \"properties\": {
      \"requestType\": \"SelfActivate\",
      \"principalId\": \"$PRINCIPAL\",
      \"roleDefinitionId\": \"$SCOPE/providers/Microsoft.Authorization/roleDefinitions/$OWNER_ROLE\",
      \"justification\": \"Incident response: payments service outage\",
      \"scheduleInfo\": {
        \"expiration\": { \"type\": \"AfterDuration\", \"duration\": \"PT4H\" }
      }
    }
  }" | jq '{id:.id,status:.properties.status}'

# rbac.tf — group-based RBAC assignments across scope levels

variable "corp_mg_id" { type = string }
variable "subscription_ids" { type = map(string) }  # name -> id
variable "groups" {
  type = object({
    platform_ops    = string  # Entra ID group object ID
    payments_team   = string
    ecommerce_team  = string
    security_audits = string
  })
}

# Platform Ops: Reader at Corp MG — inherits to all Corp subscriptions
resource "azurerm_role_assignment" "platform_reader" {
  scope                = var.corp_mg_id
  role_definition_name = "Reader"
  principal_id         = var.groups.platform_ops
}

# Security Auditors: Security Reader at Corp MG (built-in role)
resource "azurerm_role_assignment" "security_reader" {
  scope                = var.corp_mg_id
  role_definition_name = "Security Reader"
  principal_id         = var.groups.security_audits
}

# Payments team: Owner on their subscription
resource "azurerm_role_assignment" "payments_owner" {
  scope                = "/subscriptions/${var.subscription_ids["prod-payments"]}"
  role_definition_name = "Owner"
  principal_id         = var.groups.payments_team
}

# Ecommerce team: Owner on their subscription
resource "azurerm_role_assignment" "ecommerce_owner" {
  scope                = "/subscriptions/${var.subscription_ids["prod-ecommerce"]}"
  role_definition_name = "Owner"
  principal_id         = var.groups.ecommerce_team
}

# CI/CD service principals: Contributor scoped to specific resource groups only
variable "cicd_principals" {
  type = map(object({
    object_id      = string
    subscription   = string
    resource_group = string
  }))
}

resource "azurerm_role_assignment" "cicd_contributor" {
  for_each = var.cicd_principals
  scope = "/subscriptions/${var.subscription_ids[each.value.subscription]}/resourceGroups/${each.value.resource_group}"
  role_definition_name = "Contributor"
  principal_id         = each.value.object_id
}

# terraform.tfvars
corp_mg_id = "/providers/Microsoft.Management/managementGroups/mg-corp"

subscription_ids = {
  prod-payments  = "11111111-1111-1111-1111-111111111111"
  prod-ecommerce = "22222222-2222-2222-2222-222222222222"
}

groups = {
  platform_ops    = "aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa"
  payments_team   = "bbbbbbbb-bbbb-bbbb-bbbb-bbbbbbbbbbbb"
  ecommerce_team  = "cccccccc-cccc-cccc-cccc-cccccccccccc"
  security_audits = "dddddddd-dddd-dddd-dddd-dddddddddddd"
}

cicd_principals = {
  payments-api = {
    object_id      = "eeeeeeee-eeee-eeee-eeee-eeeeeeeeeeee"
    subscription   = "prod-payments"
    resource_group = "rg-api"
  }
  payments-db = {
    object_id      = "ffffffff-ffff-ffff-ffff-ffffffffffff"
    subscription   = "prod-payments"
    resource_group = "rg-db"
  }
}
